import json

def read_jsonl(path: str) -> list[dict]:
    records = []
    with open(path, encoding="utf-8") as fh:
        for lineno, line in enumerate(fh, 1):
            line = line.strip()
            if not line:
                continue
            try:
                records.append(json.loads(line))
            except json.JSONDecodeError as exc:
                raise ValueError(f"Line {lineno}: {exc}") from exc
    return records

def append_jsonl(path: str, record: dict) -> None:
    with open(path, "a", encoding="utf-8") as fh:
        fh.write(json.dumps(record, ensure_ascii=False) + "\n")

from __future__ import annotations
import csv, json, yaml
from io import StringIO
from pydantic import BaseModel, field_validator

class AgentConfig(BaseModel):
    model: str
    max_turns: int = 20
    tools: list[str] = []

    @field_validator("model")
    @classmethod
    def model_must_be_known(cls, v: str) -> str:
        allowed = {"gpt-4o", "claude-3-5-sonnet-20241022", "gemini-2.0-flash"}
        if v not in allowed:
            raise ValueError(f"Unknown model '{v}'. Choose from {allowed}.")
        return v

def load_agent_config(yaml_path: str) -> AgentConfig:
    with open(yaml_path, encoding="utf-8") as fh:
        raw = yaml.safe_load(fh)
    return AgentConfig.model_validate(raw["agent"])

def parse_csv_tool_result(csv_text: str, limit: int = 50) -> list[dict]:
    reader = csv.DictReader(StringIO(csv_text))
    rows = []
    for i, row in enumerate(reader):
        if i >= limit:
            break
        rows.append(dict(row))
    return rows

import yaml, csv, json
import xml.etree.ElementTree as ET
from pydantic import BaseModel

class Config(BaseModel):
    model: str
    max_accounts: int = 20

def load_config(path: str) -> Config:
    with open(path, encoding="utf-8") as fh:
        return Config.model_validate(yaml.safe_load(fh)["agent"])

def get_top_accounts(csv_path: str, n: int = 20) -> list[dict]:
    with open(csv_path, newline="", encoding="utf-8") as fh:
        rows = list(csv.DictReader(fh))
    rows.sort(key=lambda r: float(r.get("revenue") or 0), reverse=True)
    return rows[:n]

def parse_soap_inventory(xml_str: str) -> list[dict]:
    root = ET.fromstring(xml_str)
    return [
        {"sku": el.get("sku"), "qty": int(el.get("qty", 0))}
        for el in root.iter("item")
    ]

def log_event(path: str, event: dict) -> None:
    with open(path, "a", encoding="utf-8") as fh:
        fh.write(json.dumps(event, default=str) + "\n")

# Usage
cfg = load_config("config/agent.yaml")
accounts = get_top_accounts("data/crm_export.csv", cfg.max_accounts)
log_event("traces/run-2026-07-10.jsonl", {"event": "csv_loaded", "count": len(accounts)})
